<script>
	import { Table, TableBody, TableBodyCell, TableBodyRow, TableHead, TableHeadCell, Badge } from 'flowbite-svelte';

	// Svelte 5 Props
	let { results } = $props();

	// Derived state: Calculate yearly total and sort by cheapest first
	let sortedResults = $derived(
		results.map(plan => {
			const totalCents = plan.Data.reduce((acc, month) => acc + month.Cents, 0);
			// Normalize to yearly if data isn't exactly 12 months
			const monthCount = plan.Data.length;
			const projectedYearly = (totalCents / monthCount) * 12;
			
			return {
				...plan,
				totalCents,
				projectedYearly,
				isCredit: projectedYearly < 0
			};
		}).sort((a, b) => a.projectedYearly - b.projectedYearly)
	);

	function formatCurrency(cents) {
		const dollars = cents / 100;
		return new Intl.NumberFormat('en-US', {
			style: 'currency',
			currency: 'USD',
		}).format(dollars);
	}
</script>

<div class="relative overflow-x-auto shadow-md sm:rounded-lg">
	<Table hoverable={true}>
		<TableHead>
			<TableHeadCell>Rank</TableHeadCell>
			<TableHeadCell>Plan Name</TableHeadCell>
			<TableHeadCell>Projected Annual Cost</TableHeadCell>
			<TableHeadCell>Avg Monthly</TableHeadCell>
			<TableHeadCell>Status</TableHeadCell>
		</TableHead>
		<TableBody>
			{#each sortedResults as plan, i}
				<TableBodyRow class="group">
					<TableBodyCell class="font-medium">
						{i + 1}
					</TableBodyCell>
					<TableBodyCell>
						{plan.Name}
					</TableBodyCell>
					<TableBodyCell class={plan.isCredit ? 'text-green-600 font-bold' : 'text-gray-900'}>
						{formatCurrency(plan.projectedYearly)}
					</TableBodyCell>
					<TableBodyCell>
						{formatCurrency(plan.projectedYearly / 12)}
					</TableBodyCell>
					<TableBodyCell>
						{#if plan.isCredit}
							<Badge color="green">Net Exporter</Badge>
						{:else if plan.projectedYearly < 50000} <Badge color="blue">Efficient</Badge>
						{:else}
							<Badge color="red">High Cost</Badge>
						{/if}
					</TableBodyCell>
				</TableBodyRow>
			{/each}
		</TableBody>
	</Table>
</div>

