<script>
	import { onMount } from 'svelte';
	import { Navbar, NavBrand, NavLi, NavUl, Fileupload, Spinner, Button } from 'flowbite-svelte';
	import PlanTable from './lib/PlanTable.svelte'; // We'll build this next

	// Svelte 5 State (Runes)
	let plans = $state([]);
	let results = $state(null);
	let loading = $state(false);
	let error = $state('');

	onMount(async () => {
		try {
			const res = await fetch('/plans');
			plans = await res.json();
		} catch (e) {
			error = "Failed to load plans from server.";
		}
	});

	async function handleUpload(event) {
		const file = event.target.files[0];
		if (!file) return;

		loading = true;
		error = '';
		
		const formData = new FormData();
		formData.append('myFile', file);

		try {
			const response = await fetch('/upload', {
				method: 'POST',
				body: formData
			});
			
			if (!response.ok) throw new Error(await response.text());
			results = await response.json();
		} catch (e) {
			error = e.message;
		} finally {
			loading = false;
		}
	}
</script>

<Navbar>
	<NavBrand href="/">
		<span class="self-center whitespace-nowrap text-xl font-semibold dark:text-white">
			Solar Plan Simulator
		</span>
	</NavBrand>
	<NavUl>
		<NavLi href="https://github.com/cloudkucooland/go-greenbutton" target="_blank">GitHub</NavLi>
	</NavUl>
</Navbar>

<main class="container mx-auto p-4 space-y-8">
	<section class="bg-white dark:bg-gray-800 p-6 rounded-lg shadow-md">
		<h2 class="text-lg font-bold mb-4 dark:text-white">1. Upload SMT Data</h2>
		<p class="text-sm text-gray-500 mb-4">Upload your Smart Meter Texas CSV or Green Button XML file.</p>
		
		<Fileupload 
			id="smt-upload" 
			class="mb-2" 
			on:change={handleUpload} 
			disabled={loading}
		/>

		{#if loading}
			<div class="flex items-center space-x-2 mt-4">
				<Spinner size="4" />
				<span class="text-sm text-blue-600">Calculating 40+ solar scenarios...</span>
			</div>
		{/if}

		{#if error}
			<div class="mt-4 p-3 bg-red-100 text-red-700 rounded-md text-sm">
				Error: {error}
			</div>
		{/if}
	</section>

	{#if results}
		<section class="space-y-4">
			<h2 class="text-lg font-bold dark:text-white">2. Simulation Results</h2>
			<PlanTable {results} />
		</section>
	{/if}
</main>
